import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.List;
import java.util.Set;

@AllArgsConstructor
public class WerkbonusCalculator {

    private static final LocalDate GRENS_DATUM_NIEUWE_SLEUTEL = new LocalDate(2024, 4, 1);

    private static final Set<Sleutel<?>> WERKBONUS_SLEUTEL = ImmutableSet
            .of(SleutelCategorie.INSTANCE, SleutelPensioenStelsel.INSTANCE, SleutelWerkgeversCategorie.INSTANCE, SleutelWerknemersKengetal.INSTANCE,
                    SleutelMaatman.INSTANCE, SleutelAanstelling.INSTANCE, SleutelNaceCode.INSTANCE, SleutelDienstverband.INSTANCE,
                    SleutelVerminderingsCodeWerkbonus.INSTANCE, SleutelTypeArbeidsOvereenkomst.INSTANCE, SleutelStatuutDmfappl.INSTANCE,
                    SleutelVrijstellingTweedePensioenpijler.INSTANCE, SleutelWijzeBezoldiging.INSTANCE, SleutelMaatregelingReorganisatieArbeidsTijd.INSTANCE,
                    SleutelMaatregelingReorganisatieArbeidsTijd2.INSTANCE, SleutelVestigingsId.INSTANCE, SleutelDatumVasteBenoeming.INSTANCE,
                    SleutelSocialeMaribel.INSTANCE, SleutelMaatregelinBevorderingWerk.INSTANCE, SleutelNotieGepensioneerd.INSTANCE,
                    SleutelTypeLeerling.INSTANCE, SleutelRszDagenStelsel.INSTANCE, SleutelJaarNaarMaand.INSTANCE);


    private static final Set<Sleutel<?>> WERKBONUS_SLEUTEL_2024 = ImmutableSet
            .of(SleutelCategorie.INSTANCE, SleutelPensioenStelsel.INSTANCE, SleutelWerkgeversCategorie.INSTANCE, SleutelWerknemersKengetal.INSTANCE,
                    SleutelMaatman.INSTANCE, SleutelAanstelling.INSTANCE, SleutelNaceCode.INSTANCE, SleutelDienstverband.INSTANCE,
                    SleutelVerminderingsCodeWerkbonus.INSTANCE, SleutelTypeArbeidsOvereenkomst.INSTANCE, SleutelStatuutDmfappl.INSTANCE,
                    SleutelVrijstellingTweedePensioenpijler.INSTANCE, SleutelWijzeBezoldiging.INSTANCE, SleutelMaatregelingReorganisatieArbeidsTijd.INSTANCE,
                    SleutelVestigingsId.INSTANCE,
                    SleutelSocialeMaribel.INSTANCE, SleutelMaatregelinBevorderingWerk.INSTANCE, SleutelNotieGepensioneerd.INSTANCE,
                    SleutelTypeLeerling.INSTANCE, SleutelRszDagenStelsel.INSTANCE, SleutelJaarNaarMaand.INSTANCE,
                    SleutelParitaitComite.INSTANCE, SleutelGedetacheerd.INSTANCE, SleutelVrijstellingCapelo.INSTANCE, SleutelSectorDetail.INSTANCE,
                    SleutelActiviteitTovRisico.INSTANCE, SleutelRegionaleTwerkstellingsMaatregel.INSTANCE, SleutelUrenGesubsidieerd.INSTANCE
            );


    private final WerkbonusBasisBedragFactory basisBedragFactory;
    private final WerkbonusKomtInAanmerking komtInAanMerking;
    private final WerkbonusReferentieLoon werkbonusReferentieLoon;

    public Money bereken(RekenContext opdrachtContext, Opdracht opdracht, WerkbonusLuik werkbonusLuik) {
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        RegulManager regulManager = opdrachtContext.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
        LoonElementManager manager = opdrachtContext.getUnchecked(RekenChainKey.LOONELEMENT_MANAGER_KEY);
        RkmCoreHrConfiguratieManager rkmCoreHrConfiguratieManager = opdrachtContext.getUnchecked(RekenChainKey.RKM_COREHR_CONFIG_MANAGER);
        SleutelSamenNemer aggregator = new SleutelSamenNemer();
        List<SleutelGegevens> aggregaten = aggregator.neemSamenVoorSleutel(opdracht, getWerkbonusSleutel(rekenTijd));
        Money totaalBedragVermindering = Money.ZERO;
        for (SleutelGegevens aggregaat : aggregaten) {
            if (komtInAanMerking.checkSleutelGegevens(aggregaat, rekenTijd, regulManager, rkmCoreHrConfiguratieManager)) {
                Money bedragVermindering = berekenSleutelGegevens(aggregaat, rekenTijd, opdrachtContext, opdracht, manager, werkbonusLuik);
                totaalBedragVermindering = totaalBedragVermindering.add(bedragVermindering);
            }
        }

        return totaalBedragVermindering;
    }

    private Set<Sleutel<?>> getWerkbonusSleutel(RekenTijd rekenTijd) {
        if (rekenTijd.beginDatum.isBefore(GRENS_DATUM_NIEUWE_SLEUTEL)) {
            return WERKBONUS_SLEUTEL;
        } else {
            return WERKBONUS_SLEUTEL_2024;
        }
    }


    private Money berekenSleutelGegevens(
            SleutelGegevens aggregaat, RekenTijd rekenTijd, RekenContext opdrachtContext, Opdracht opdracht, LoonElementManager manager, WerkbonusLuik werkbonusLuik) {
        PrestatieSamenvatting prestatieSamenvatting = aggregaat.getPrestatieSamenvatting(opdrachtContext);
        BigDecimal referentieUren = getReferentieUren(rekenTijd, opdrachtContext, opdracht);
        Money referentieLoon = werkbonusReferentieLoon.bereken(manager, prestatieSamenvatting, aggregaat, rekenTijd, referentieUren);
        if (referentieLoon.signum() > 0) {
            Money basisBedrag = basisBedragFactory.bereken(aggregaat, referentieLoon, rekenTijd, werkbonusLuik);
            return berekeningVermindering(prestatieSamenvatting, aggregaat, basisBedrag, rekenTijd, referentieUren);
        } else {
            return Money.ZERO;
        }
    }

    private BigDecimal getReferentieUren(RekenTijd rekenTijd, RekenContext opdrachtContext, Opdracht opdracht) {
        RkmCoreHrConfiguratieManager rkmCoreHrConfiguratieManager = opdrachtContext.getUnchecked(RekenChainKey.RKM_COREHR_CONFIG_MANAGER);
        RkmCoreHrConfiguratie rkmCoreHrConfiguratie = rkmCoreHrConfiguratieManager.getRkmCoreHrConfiguratie(opdracht, rekenTijd);
        if (rkmCoreHrConfiguratie != null) {
            return rkmCoreHrConfiguratie.getReferentieUren();
        } else {
            return RekenTools.ACHTENDERTIG;
        }
    }

    private Money berekeningVermindering(
            PrestatieSamenvatting prestatieSamenvatting, SleutelGegevens gegevens, Money basisBedrag, RekenTijd rekenTijd, BigDecimal referentieMaatman) {
        BigDecimal hWaarde = prestatieSamenvatting.getHwaarde();
        BigDecimal weekdagen = AantalRszDagen.inMaand(5, rekenTijd.rekenPeriode);
        BigDecimal maatman = gegevens.getMaatman();
        if (RekenTools.isOnregelmatigPerPrestatieOfPerUur(maatman)) {
            maatman = referentieMaatman;
        }
        BigDecimal uren = maatman.multiply(weekdagen).divide(BigDecimal.valueOf(5), 3, RoundingMode.HALF_UP);
        if (uren.signum() == 0) {
            uren = BigDecimal.ONE;
        }

        BigDecimal verhouding = hWaarde.divide(uren, 2, RoundingMode.HALF_UP).min(BigDecimal.ONE);
        return basisBedrag.multiply(verhouding).round(2);
    }
}
